import{_ as a,a as i,b as o}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Uso del blog","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/blog.md","filePath":"es/Other/blog.md","lastUpdated":1781962217000}'),c={name:"es/Other/blog.md"};function d(n,e,p,u,b,g){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="uso-del-blog" tabindex="-1">Uso del blog <a class="header-anchor" href="#uso-del-blog" aria-label="Permalink to &quot;Uso del blog&quot;">​</a></h1><p>La función de blog añade una página de blog independiente a tu sitio ImgBed.</p><p>Cuando esté activada, los visitantes podrán entrar desde:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/blog/</span></span></code></pre></div><p><img src="'+a+'" alt="Página principal del blog" loading="lazy"></p><p>El blog está adaptado a partir del proyecto de código abierto <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed lo reescribe e integra con Vue para que funcione como parte del sitio de alojamiento de archivos.</p><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; Blog</span></span></code></pre></div><p><img src="'+i+'" alt="Ajustes del blog" loading="lazy"></p><h2 id="primer-uso" tabindex="-1">Primer uso <a class="header-anchor" href="#primer-uso" aria-label="Permalink to &quot;Primer uso&quot;">​</a></h2><ol><li>Activa el interruptor <code>Habilitar</code>.</li><li>Elige la cuenta de GitHub donde se guardará la configuración del blog.</li><li>Haz clic en <code>Actualizar blog</code>.</li><li>Espera el mensaje de actualización correcta.</li><li>Abre <code>https://tu-dominio/blog/</code> para comprobar el resultado.</li></ol><p>En el primer uso, ImgBed prepara un repositorio privado en la cuenta de GitHub seleccionada:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Ese repositorio guarda la configuración del blog y el contenido de los artículos.</p><h2 id="como-escribir-articulos" tabindex="-1">Cómo escribir artículos <a class="header-anchor" href="#como-escribir-articulos" aria-label="Permalink to &quot;Cómo escribir artículos&quot;">​</a></h2><p>Los artículos se editan en tu repositorio privado de GitHub:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Flujo habitual:</p><ol><li>Abre GitHub.</li><li>Entra en el repositorio <code>imgbed-blog-config</code>.</li><li>Crea o modifica archivos de artículos.</li><li>Guarda los cambios con un commit.</li><li>Vuelve al panel de administración de ImgBed y pulsa <code>Actualizar blog</code>. También puedes hacer clic tres veces en el logotipo de la esquina superior izquierda del blog para forzar la actualización.</li></ol><p><code>Actualizar blog</code> no sobrescribe los artículos que ya escribiste. Se usa sobre todo para inicializar el repositorio o refrescar la caché del blog.</p><h2 id="funciones-disponibles" tabindex="-1">Funciones disponibles <a class="header-anchor" href="#funciones-disponibles" aria-label="Permalink to &quot;Funciones disponibles&quot;">​</a></h2><p>El blog incluye listado de artículos, categorías, etiquetas, archivo, búsqueda, modo oscuro y cambio de idioma.</p><p>También admite comentarios y estadísticas de visitas.</p><p><img src="'+o+'" alt="Comentarios del blog" loading="lazy"></p><p>Los comentarios aparecen debajo de cada artículo. El visitante puede enviar avatar, apodo, correo electrónico y contenido del comentario.</p><p>Las estadísticas muestran visitas de artículos y visitas del sitio, útiles para entender el tráfico del blog.</p><h2 id="direccion-de-acceso" tabindex="-1">Dirección de acceso <a class="header-anchor" href="#direccion-de-acceso" aria-label="Permalink to &quot;Dirección de acceso&quot;">​</a></h2><p>El blog siempre se publica bajo <code>/blog/</code>.</p><p>Si tu dominio de ImgBed es:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>la dirección del blog será:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Si desactivas el blog, los visitantes ya no podrán acceder a esa página.</p>',33)])])}const f=s(c,[["render",d]]);export{v as __pageData,f as default};
